import random
import re

class SimpleChatbot:
    def __init__(self):
        self.responses = {
            'greeting': ['Hello!', 'Hi there!', 'Hey!'],
            'question': ['I think so.', 'Maybe?', 'Tell me more.'],
            'statement': ['Interesting!', 'I see.', 'Really?']
        }

    def generate_response(self, user_input):
        user_input = user_input.lower()

        # Check for question marks
        if '?' in user_input:
            return random.choice(self.responses['question'])
        # Check for greetings
        elif any(word in user_input for word in ['hello', 'hi', 'hey']):
            return random.choice(self.responses['greeting'])
        # Default to statement responses
        else:
            return random.choice(self.responses['statement'])

# Example usage for Turing Test simulation
chatbot = SimpleChatbot()
print("Turing Test Demo - Simple Chatbot:")
print("Chatbot:", chatbot.generate_response("Hello!"))
print("Chatbot:", chatbot.generate_response("How are you?"))
print("Chatbot:", chatbot.generate_response("I like cats."))
